121	/// True if `actual` (a config key from a loaded config file) is
122	/// recognized by some `schema()` entry whose homes satisfy
123	/// `home_pred`.
124	///
125	/// - Non-dynamic entries match by exact path equality.
126	/// - Dynamic entries (`key.dynamic`) match segment-wise: equal
127	///   segment counts, each entry segment either equal to the actual
128	///   segment or a `<placeholder>` matching any single segment.
129	fn key_known(actual: &str, home_pred: impl Fn(&[Home]) -> bool) -> bool {
130	    schema().iter().any(|key| {
131	        if !home_pred(key.homes) {
132	            return false;
133	        }
134	        if !key.dynamic {
135	            return key.path == actual;
136	        }
137	        let entry_segs: Vec<&str> = key.path.split('.').collect();
138	        let actual_segs: Vec<&str> = actual.split('.').collect();
139	        entry_segs.len() == actual_segs.len()
140	            && entry_segs
141	                .iter()
142	                .zip(actual_segs.iter())
143	                .all(|(e, a)| e == a || (e.starts_with('<') && e.ends_with('>')))
144	    })
145	}
146	
147	/// Validate one config file against the schema, filtered to the
148	/// homes accepted at that file by `home_pred`.
149	///
150	/// - A missing file is not an error — `info!`s that it's absent
151	///   and returns `Ok(0)`.
152	/// - Each key not recognized by `key_known` is reported with
153	///   `warn!`, naming `label` and the key; keys are checked in
154	///   sorted order for stable output.
155	/// - Returns the count of unknown keys found. A load error
156	///   (malformed TOML) propagates as `Err`.
157	fn validate_file(
158	    path: &std::path::Path,
159	    label: &str,
160	    home_pred: impl Fn(&[Home]) -> bool,
161	) -> Result<usize, Box<dyn Error>> {
162	    if !path.exists() {
163	        info!("{label}: {} not found — skipping", path.display());
164	        return Ok(0);
165	    }
166	    let map = toml_load(path)?;
167	    let mut keys: Vec<&String> = map.keys().collect();
168	    keys.sort();
169	
170	    let mut unknown = 0;
171	    for key in keys {
172	        if !key_known(key, &home_pred) {
173	            warn!("{label} ({}): unknown key {key:?}", path.display());
174	            unknown += 1;
175	        }
176	    }
177	    Ok(unknown)
178	}
179	
180	/// Validate the selected home(s)' config file(s) against the
181	/// schema, returning the total count of unknown keys.
182	fn validate(params: &ConfigParams) -> Result<usize, Box<dyn Error>> {
183	    let mut unknown = 0;
184	
185	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
186	        unknown += validate_file(&config_path()?, "user config", |homes| {
187	            homes.contains(&Home::User)
188	        })?;
189	    }
190	
191	    if matches!(params.home, HomeFilter::Workspace | HomeFilter::All) {
192	        match find_workspace_root() {
193	            Some(root) => {
194	                unknown +=
195	                    validate_file(&root.join(VC_CONFIG_FILE), "workspace config", |homes| {
196	                        homes.contains(&Home::WorkspaceCode) || homes.contains(&Home::WorkspaceBot)
197	                    })?;
198	            }
199	            None => info!("workspace config: not inside a workspace — skipping"),
200	        }
201	    }
202	
203	    Ok(unknown)
204	}
205	
206	/// Print the settable config schema, grouped by config home then
207	/// TOML section (`--home` selects which home group(s) to print),
208	/// or — with `--validate` — check the config file(s) for unknown
209	/// keys and exit non-zero if any are found.
210	pub fn config(_ctx: &Context, params: &ConfigParams) -> Result<(), Box<dyn std::error::Error>> {
211	    if params.validate {
212	        let total = validate(params)?;
213	        return if total > 0 {
214	            Err(format!("config: {total} unknown key(s) found").into())
215	        } else {
216	            info!("config: all keys recognized");
217	            Ok(())
218	        };
219	    }
220	
221	    info!(
222	        "# vc-x1 settable config keys (from vc-x1 {})",
223	        env!("CARGO_PKG_VERSION")
224	    );
225	    info!("# Keys below are shown at their built-in default (commented");
226	    info!("# unless required); run `vc-x1 config --validate` to check a");
227	    info!("# config file's keys against this schema.");
228	    info!("");
229	
230	    let all_keys = schema();
231	
232	    if matches!(params.home, HomeFilter::User | HomeFilter::All) {
233	        let user_keys: Vec<&ConfigKey> = all_keys.iter().filter(|k| in_user_group(k)).collect();
